#
# ROM size optimization: version_script for
# libnotification_subscriber_extension_module.z.so.
# Only the napi_module entry symbol is exported; all other symbols are
# hidden to reduce .dynstr/.dynsym/.plt section sizes. Module registration
# still works because the __attribute__((constructor)) in the extension
# module loader runs via .init_array, which is independent of symbol
# visibility.

1.0 {
  global:
    napi_module;
  local:
    *;
};
